using System;
using System.Data.SqlClient;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.Extensions.Logging;

public static class ReportingApiFunction
{
    [FunctionName("ReportingApiFunction")]
    public static IActionResult Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", Route = null)] HttpRequestData req,
        ILogger logger)
    {
        try
        {
            var requestBody = new StreamReader(req.Body).ReadToEnd();
            dynamic data = JsonConvert.DeserializeObject(requestBody);

            string connectionString = Environment.GetEnvironmentVariable("AzureSQLConnectionString");
            if (string.IsNullOrEmpty(connectionString))
                return new StatusCodeResult(StatusCodes.Status500InternalServerError);

            string query = $"SELECT * FROM YourTable WHERE 1=1";

            if (data.filterColumn != null)
            {
                query += $" AND {data.filterColumn} = '{data.filterValue}'";
            }

            using (SqlConnection connection = new SqlConnection(connectionString))
            {
                connection.Open();

                SqlCommand command = new SqlCommand(query, connection);
                SqlDataReader reader = command.ExecuteReader();

                List<YourTable> results = new List<YourTable>();

                while (reader.Read())
                {
                    YourTable table = new YourTable
                    {
                        Column1 = reader["Column1"].ToString(),
                        Column2 = reader["Column2"].ToString()
                    };
                    results.Add(table);
                }

                return new OkObjectResult(results);
            }
        }
        catch (Exception ex)
        {
            logger.LogError($"An error occurred: {ex.Message}");
            return new StatusCodeResult(StatusCodes.Status500InternalServerError);
        }
